class CDB {
    constructor(request) {
        this.layout = new CDBLayout();
        this.cart = new Cart();

        this.modules = {};

        this.dispatch()
    }

    dispatch() {
        if (request.module === 'default'){
            if (request.controller === 'homepage' && request.action === 'index') {
                this.modules['homepage'] = new Homepage();
            }
            if (request.controller !== 'login'){
                this.modules['videohelp'] = new Videohelp();
            }
        }
    }
}